) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;

--
-- Đang đổ dữ liệu cho bảng `wp_3_posts`
--

INSERT INTO `wp_3_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(1, 4, '2026-04-13 07:34:06', '2026-04-13 07:34:06', 'Chào mừng bạn đến với <a href=\"http://localhost/wordpress/\">My Multisite Network</a>. Đây là bài viết đầu tiên của bạn. Bạn có thể sửa hoặc xoá nó, sau đó bắt đầu viết bài nào!', 'Chào tất cả mọi người!', '', 'publish', 'open', 'open', '', 'chao-moi-nguoi', '', '', '2026-04-13 07:34:06', '2026-04-13 07:34:06', '', 0, 'http://localhost/wordpress/siteb/?p=1', 0, 'post', '', 1),
(2, 4, '2026-04-13 07:34:06', '2026-04-13 07:34:06', '<!-- wp:paragraph -->\n<p>Đây là trang mẫu. Nó khác với bài viết bởi vì nó thường cố định và hiển thị trong menu của bạn. Nhiều người bắt đầu với trang Giới thiệu nơi bạn chia sẻ thông tin cho những ai ghé thăm. Nó có thể bắt đầu như thế này:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Chào bạn! Tôi là một người bán hàng, và đây là website của tôi. Tôi sống ở Hà Nội, có một gia đình nhỏ, và tôi thấy cách sử dụng WordPress rất thú vị.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>... hoặc cái gì đó như thế này:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Công ty chúng tôi được thành lập năm 2010, và cung cấp dịch vụ chất lượng cho rất nhiều sự kiện tại khắp Việt Nam. Với văn phòng đặt tại Hà Nội, TP. Hồ Chí Minh cùng hơn 40 nhân sự, chúng tôi là nơi nhiều đối tác tin tưởng giao cho tổ chức các sự kiện lớn.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>Là một người dùng WordPress mới, bạn nên ghé thăm <a href=\"http://localhost/wordpress/siteb/wp-admin/\">bảng điều khiển</a> để xóa trang này và tạo trang mới cho nội dung của chính bạn. Chúc bạn vui vẻ!</p>\n<!-- /wp:paragraph -->', 'Trang mẫu', '', 'publish', 'closed', 'open', '', 'trang-mau', '', '', '2026-04-13 07:34:06', '2026-04-13 07:34:06', '', 0, 'http://localhost/wordpress/siteb/?page_id=2', 0, 'page', '', 0),
(3, 1, '2026-04-13 07:36:01', '0000-00-00 00:00:00', '', 'Lưu nháp tự động', '', 'auto-draft', 'open', 'open', '', '', '', '', '2026-04-13 07:36:01', '0000-00-00 00:00:00', '', 0, 'http://localhost/wordpress/siteb/?p=3', 0, 'post', '', 0),
(4, 1, '2026-04-13 07:44:22', '0000-00-00 00:00:00', '', 'Lưu nháp tự động', '', 'auto-draft', 'open', 'open', '', '', '', '', '2026-04-13 07:44:22', '0000-00-00 00:00:00', '', 0, 'http://localhost/wordpress/siteb/?p=4', 0, 'post', '', 0),
(5, 1, '2026-04-13 07:44:26', '2026-04-13 07:44:26', '<!-- wp:page-list /-->', 'Điều hướng', '', 'publish', 'closed', 'closed', '', 'navigation', '', '', '2026-04-13 07:44:26', '2026-04-13 07:44:26', '', 0, 'http://localhost/wordpress/siteb/2026/04/13/navigation/', 0, 'wp_navigation', '', 0);

